import { describe, expect, it, vi } from "vitest";
import { handleStudioError, openStudioTo, StudioNavigationError, } from "./openStudioTo.js";
const mockEmitJson = vi.fn();
vi.mock("../output.js", () => ({
    emitJson: (...args) => mockEmitJson(...args),
}));
const mockClearActiveStudioSession = vi.fn();
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
const mockWriteActiveStudioSession = vi.fn();
const mockNavigateStudioAndAwaitAck = vi
    .fn()
    .mockResolvedValue({ acked: false, reason: "timeout" });
const mockPollLoginEvents = vi.fn();
const mockPollAgentSessionEvents = vi
    .fn()
    .mockReturnValue(new Promise(() => { }));
const mockHasCredentials = vi.fn().mockReturnValue(true);
const mockGetConfig = vi.fn().mockReturnValue({
    serviceUrl: "https://test.invalid",
    apiKey: "test-key",
});
vi.mock("../activeStudioSession.js", () => ({
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
    clearActiveStudioSession: (...args) => mockClearActiveStudioSession(...args),
    writeActiveStudioSession: (...args) => mockWriteActiveStudioSession(...args),
}));
vi.mock("./createStudioSession.js", () => ({
    createStudioSession: vi.fn().mockResolvedValue({
        sessionId: "new-session",
        serviceUrl: "https://test.invalid",
    }),
}));
const mockFetchStreamTip = vi.fn().mockResolvedValue("tip-42");
vi.mock("../agentSessionChannel.js", () => ({
    fetchStreamTip: (...args) => mockFetchStreamTip(...args),
    navigateStudioAndAwaitAck: (...args) => mockNavigateStudioAndAwaitAck(...args),
    pollAgentSessionEvents: (...args) => mockPollAgentSessionEvents(...args),
    pollLoginEvents: (...args) => mockPollLoginEvents(...args),
}));
vi.mock("../browser.js", () => ({
    openChromelessWindow: vi.fn(),
}));
vi.mock("../frontmostApp.js", () => ({
    recordFocus: () => () => { },
}));
vi.mock("../config.js", () => ({
    saveCredentials: vi.fn(),
    getConfig: (...args) => mockGetConfig(...args),
    hasCredentials: (...args) => mockHasCredentials(...args),
}));
const mockWaitForSessionReady = vi.fn().mockResolvedValue(undefined);
vi.mock("./sessionReady.js", () => ({
    waitForSessionReady: (...args) => mockWaitForSessionReady(...args),
}));
describe("openStudioTo", () => {
    it("performs inline login when not authenticated", async () => {
        mockHasCredentials.mockReturnValueOnce(false);
        mockPollLoginEvents.mockResolvedValueOnce("test-api-key");
        const onLoginRequired = vi.fn();
        const onAuthenticated = vi.fn();
        const result = await openStudioTo("/studio", {
            onLoginRequired,
            onAuthenticated,
        });
        expect(onLoginRequired).toHaveBeenCalledOnce();
        expect(onAuthenticated).toHaveBeenCalledOnce();
        expect(result.opened).toBe(true);
        expect(result.apiKey).toBe("test-api-key");
        const { openChromelessWindow } = await import("../browser.js");
        expect(openChromelessWindow).toHaveBeenCalledWith(expect.stringContaining("/studio/sign-in?redirect_url="));
        const signInUrl = openChromelessWindow.mock
            .calls[0][0];
        // onLoginRequired receives the same sign-in URL that was opened, so callers
        // can surface it to the user if the browser fails to open.
        expect(onLoginRequired).toHaveBeenCalledWith(expect.any(String), signInUrl);
        const redirectUrl = decodeURIComponent(signInUrl.split("redirect_url=")[1]);
        const pluginLoginCount = (redirectUrl.match(/pluginLogin=true/g) ?? [])
            .length;
        expect(pluginLoginCount).toBeLessThanOrEqual(1);
        // No onEvent, so no poller and no session write on the login path.
        expect(mockWriteActiveStudioSession).not.toHaveBeenCalled();
    });
    it("gates (throws) and never opens a duplicate when an active session does not respond", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        const createBefore = createStudioSession.mock
            .calls.length;
        await expect(openStudioTo("/studio")).rejects.toThrow("Studio navigation failed: timeout");
        // A no-ack must NOT fall back to opening a fresh window over a believed-live
        // record. The pointer is preserved for an explicit clear + retry.
        expect(createStudioSession.mock.calls.length).toBe(createBefore);
        expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
    });
    it("gates (throws) when the window closed mid-navigation", async () => {
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "window-closed",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        await expect(openStudioTo("/studio")).rejects.toThrow("Studio navigation failed: window-closed");
    });
    it("gates (throws) when a live tab blocks the navigation", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "blocked",
            blockedReason: "unsaved changes",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        const createBefore = createStudioSession.mock
            .calls.length;
        await expect(openStudioTo("/studio")).rejects.toThrow("blocked");
        expect(createStudioSession.mock.calls.length).toBe(createBefore);
    });
    it("reuses the existing tab when it acks", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({ acked: true });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        const createBefore = createStudioSession.mock
            .calls.length;
        const result = await openStudioTo("/studio");
        expect(mockNavigateStudioAndAwaitAck).toHaveBeenCalled();
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("existing-session");
        expect(createStudioSession.mock.calls.length).toBe(createBefore);
    });
    it("opens a fresh Studio when no active session is recorded", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        const navBefore = mockNavigateStudioAndAwaitAck.mock.calls.length;
        // mockReadActiveStudioSession default returns null (no record).
        const result = await openStudioTo("/studio");
        // No record means no handshake; open fresh.
        expect(mockNavigateStudioAndAwaitAck.mock.calls.length).toBe(navBefore);
        expect(createStudioSession).toHaveBeenCalled();
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
    });
});
describe("handleStudioError", () => {
    it("emits not-responding for an unreachable session (timeout)", () => {
        const exit = vi
            .spyOn(process, "exit")
            .mockImplementation((() => undefined));
        mockEmitJson.mockClear();
        handleStudioError(new StudioNavigationError("timeout", undefined, "sess-1"));
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "not-responding",
            sessionId: "sess-1",
        });
        exit.mockRestore();
    });
    it("emits open-failed (NOT not-responding) when a live tab blocks the nav", () => {
        const exit = vi
            .spyOn(process, "exit")
            .mockImplementation((() => undefined));
        mockEmitJson.mockClear();
        handleStudioError(new StudioNavigationError("blocked", "unsaved changes", "sess-1"));
        // A blocked tab is alive and refused — surface it, never offer clear+reopen.
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "open-failed",
            reason: "unsaved changes",
        });
        expect(mockEmitJson).not.toHaveBeenCalledWith(expect.objectContaining({ event: "not-responding" }));
        exit.mockRestore();
    });
});
const GRACE_MS = 10_000;
// The poller is the only place that clears a pointer automatically, and it must
// do so ONLY on proof the window is gone (`studio:window-closed`, the
// beforeunload beacon), never on the logical `session-ended` or the
// informational `session-closed`. These drive the internal poller callback
// openStudioTo hands to pollAgentSessionEvents and assert exactly when the
// clear fires.
describe("openStudioTo event poller", () => {
    async function startPoller() {
        mockClearActiveStudioSession.mockClear();
        const callerOnEvent = vi.fn();
        const callsBefore = mockPollAgentSessionEvents.mock.calls.length;
        // No record -> new-session path -> startEventPoller -> pollAgentSessionEvents.
        await openStudioTo("/studio", { onEvent: callerOnEvent });
        // The poller attaches asynchronously (it fetches the stream tip first);
        // flush microtasks until the poll call lands.
        for (let i = 0; i < 20; i++) {
            if (mockPollAgentSessionEvents.mock.calls.length > callsBefore) {
                break;
            }
            await Promise.resolve();
        }
        const lastCall = mockPollAgentSessionEvents.mock.calls.at(-1)?.[0];
        return { poll: lastCall.onEvent, callerOnEvent, pollOpts: lastCall };
    }
    function sessionEndedCount(callerOnEvent) {
        return callerOnEvent.mock.calls.filter(([event]) => event.type === "studio:session-ended").length;
    }
    it("attaches strictly after the stream tip so replayed history can't drive the lifecycle", async () => {
        const { pollOpts } = await startPoller();
        // Reused sessions legitimately carry an old session-ended (the ended-but-
        // alive window is reusable by design); replaying it would instantly
        // terminate the command. The poller must start at the pre-attach tip.
        expect(pollOpts.startCursor).toBe("tip-42");
    });
    it("clears after the grace window on window-closed (real teardown)", async () => {
        vi.useFakeTimers();
        try {
            const { poll, callerOnEvent } = await startPoller();
            poll({ type: "studio:window-closed", data: {} });
            // Within the grace window a refresh could still reconnect: don't clear yet.
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
            vi.advanceTimersByTime(GRACE_MS + 1);
            expect(mockClearActiveStudioSession).toHaveBeenCalledWith("new-session");
            // The command gets one synthetic session-ended so its terminal logic runs.
            expect(callerOnEvent).toHaveBeenCalledWith(expect.objectContaining({ type: "studio:session-ended" }));
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("does NOT clear when a refresh reconnects within the grace window", async () => {
        vi.useFakeTimers();
        try {
            const { poll } = await startPoller();
            poll({ type: "studio:window-closed", data: {} });
            poll({ type: "studio:session-started", data: {} });
            vi.advanceTimersByTime(GRACE_MS + 1);
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("forwards session-ended to the command but NEVER clears (logical end only)", async () => {
        vi.useFakeTimers();
        try {
            const { poll, callerOnEvent } = await startPoller();
            poll({ type: "studio:session-ended", data: {} });
            // The command terminates on the forwarded event, but the pointer is
            // kept: window.close() may have been refused and the window (parked on
            // the close page) is still alive and reusable by the next open.
            expect(callerOnEvent).toHaveBeenCalledWith(expect.objectContaining({ type: "studio:session-ended" }));
            vi.advanceTimersByTime(GRACE_MS * 2);
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("ignores session-closed entirely (close flow completed, not proof)", async () => {
        vi.useFakeTimers();
        try {
            const { poll, callerOnEvent } = await startPoller();
            poll({ type: "studio:session-closed", data: {} });
            vi.advanceTimersByTime(GRACE_MS * 2);
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
            expect(sessionEndedCount(callerOnEvent)).toBe(0);
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("cancels a pending window-closed grace when session-ended arrives (live window proof)", async () => {
        vi.useFakeTimers();
        try {
            const { poll, callerOnEvent } = await startPoller();
            // Refresh teardown arms the grace timer...
            poll({ type: "studio:window-closed", data: {} });
            // ...then a session-ended (only live page JS emits it) proves the window
            // is alive: the stale timer must not fire and clear a live pointer.
            poll({ type: "studio:session-ended", data: {} });
            vi.advanceTimersByTime(GRACE_MS * 2);
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
            expect(sessionEndedCount(callerOnEvent)).toBe(1);
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("clears on the window-closed confirming a deliberate end, forwarding exactly one session-ended", async () => {
        vi.useFakeTimers();
        try {
            const { poll, callerOnEvent } = await startPoller();
            poll({ type: "studio:session-ended", data: {} });
            poll({ type: "studio:window-closed", data: {} });
            vi.advanceTimersByTime(GRACE_MS + 1);
            expect(mockClearActiveStudioSession).toHaveBeenCalledWith("new-session");
            expect(sessionEndedCount(callerOnEvent)).toBe(1);
        }
        finally {
            vi.useRealTimers();
        }
    });
});
